<script>
$(function(){let trendChart,deviceChart;const esc=v=>$('<div>').text(v??'').html();const list=(rows,valueKey='value')=>(rows||[]).map(x=>`<div class="d-flex justify-content-between border-bottom py-2"><span>${esc(x.label||'Bilinmiyor')}</span><strong>${Number(x[valueKey]||0).toLocaleString('tr-TR')}</strong></div>`).join('')||'<span class="text-muted">Veri yok</span>';
