function chart(data){const labels=(data||[]).map(x=>x.day),visitors=(data||[]).map(x=>x.visitors),views=(data||[]).map(x=>x.pageviews);if(trendChart)trendChart.destroy();trendChart=new Chart($('#trendChart'),{type:'line',data:{labels,datasets:[{label:'Ziyaretçi',data:visitors,borderColor:'#38bdf8',tension:.35},{label:'Sayfa görüntüleme',data:views,borderColor:'#8b5cf6',tension:.35}]},options:{responsive:true,maintainAspectRatio:false}})}
async function load(){const r=await $.getJSON('../ajax/visitor-analytics.php',{range:$('#range').val()}).catch(()=>null);if(!r?.success){$('#recent').html('<tr><td colspan="6" class="text-danger">Veriler alınamadı. SQL migrationını kontrol edin.</td></tr>');return}const d=r.data,s=d.summary;$('#metrics').html([['Anlık',s.active_now,'bi-broadcast'],['Tekil ziyaretçi',s.visitors,'bi-people'],['Oturum',s.sessions,'bi-window-stack'],['Sayfa görüntüleme',s.pageviews,'bi-eye'],['Ort. sayfa/oturum',s.avg_pages,'bi-graph-up']].map(x=>`<div class="col-6 col-xl"><div class="card soft-card h-100"><div class="card-body"><i class="bi ${x[2]} text-primary"></i><div class="va-metric">${Number(x[1]||0).toLocaleString('tr-TR')}</div><div class="text-muted small">${x[0]}</div></div></div></div>`).join(''));renderMap(d.active);chart(d.trend);if(deviceChart)deviceChart.destroy();deviceChart=new Chart($('#deviceChart'),{type:'doughnut',data:{labels:d.devices.map(x=>x.label),datasets:[{data:d.devices.map(x=>x.value),backgroundColor:['#38bdf8','#8b5cf6','#22c55e','#f59e0b']}]},options:{plugins:{legend:{position:'bottom'}}}});$('#countries').html(list(d.countries));$('#sources').html(list(d.sources));$('#pages').html(list(d.pages,'views'));$('#recent').html(d.recent.map(x=>`<tr><td><strong>${esc(x.full_name||'Anonim')}</strong><div class="small text-muted">${x.user_id?'Kayıtlı':'Anonim'}</div></td><td>${esc(x.country_name||'Bilinmiyor')}</td><td>${esc(x.device_type)} · ${esc(x.browser_name)}<div class="small text-muted">${esc(x.os_name)}</div></td><td class="text-break">${esc(x.last_path)}</td><td>${x.pageview_count}</td><td>${esc(x.last_seen_at)}</td></tr>`).join('')||'<tr><td colspan="6">Veri yok</td></tr>');$('#updated').text('Son güncelleme: '+new Date().toLocaleTimeString('tr-TR'))}
